--
-- Name: customer_cross_activity; Type: VIEW; Schema: public; Owner: admin
--

CREATE VIEW public.customer_cross_activity AS
 SELECT c.customer_id,
    (((c.first_name)::text || ' '::text) || (c.last_name)::text) AS customer_name,
    COALESCE(lt.level, 'No Loyalty'::character varying) AS tier_level,
    res.nb_reservations,
    ord.nb_orders,
    ord.total_revenue,
        CASE
            WHEN ((ord.nb_orders = 0) AND (res.nb_reservations > 0)) THEN 'Reservation only'::text
            WHEN ((ord.nb_orders > 0) AND (res.nb_reservations = 0)) THEN 'Order only'::text
            WHEN ((ord.nb_orders > 0) AND (res.nb_reservations > 0)) THEN 'Both'::text
            ELSE 'Inactive'::text
        END AS engagement_type
   FROM ((((public.customer c
     LEFT JOIN public.loyalty l ON ((c.customer_id = l.customer_id)))
     LEFT JOIN public.loyalty_tier lt ON ((l.tier_id = lt.tier_id)))
     LEFT JOIN LATERAL ( SELECT count(*) AS nb_reservations
           FROM public.reservation r
          WHERE (r.customer_id = c.customer_id)) res ON (true))
     LEFT JOIN LATERAL ( SELECT count(*) AS nb_orders,
            COALESCE(sum(b.final_amount), (0)::numeric) AS total_revenue
           FROM (public."ORDER" o
             LEFT JOIN public.bill b ON ((o.order_id = b.order_id)))
          WHERE (o.customer_id = c.customer_id)) ord ON (true));


ALTER VIEW public.customer_cross_activity OWNER TO admin;

