--
-- Name: customer_loyalty_status; Type: VIEW; Schema: public; Owner: admin
--

CREATE VIEW public.customer_loyalty_status AS
 SELECT c.customer_id,
    (((c.first_name)::text || ' '::text) || (c.last_name)::text) AS customer_name,
    COALESCE(lt.level, 'No Loyalty'::character varying) AS tier_level,
    COALESCE(l.points, 0) AS current_points,
    count(DISTINCT lx.transaction_id) AS loyalty_tx_count,
    count(DISTINCT r.reservation_id) AS total_reservations,
    max(r.datetime) AS last_reservation_date
   FROM ((((public.customer c
     LEFT JOIN public.loyalty l ON ((c.customer_id = l.customer_id)))
     LEFT JOIN public.loyalty_tier lt ON ((l.tier_id = lt.tier_id)))
     LEFT JOIN public.loyalty_transaction lx ON ((l.loyalty_id = lx.loyalty_id)))
     LEFT JOIN public.reservation r ON ((c.customer_id = r.customer_id)))
  GROUP BY c.customer_id, c.first_name, c.last_name, lt.level, l.points;


ALTER VIEW public.customer_loyalty_status OWNER TO admin;

--
-- Name: customer_order_summary; Type: VIEW; Schema: public; Owner: admin
--

CREATE VIEW public.customer_order_summary AS
 SELECT c.customer_id,
    (((c.first_name)::text || ' '::text) || (c.last_name)::text) AS customer_name,
    c.email,
    count(DISTINCT o.order_id) AS total_orders,
    COALESCE(sum(b.final_amount), (0)::numeric) AS total_spent,
    COALESCE(round(avg(b.final_amount), 2), (0)::numeric) AS avg_bill_amount,
    max(o.order_time) AS last_order_time
   FROM ((public.customer c
     LEFT JOIN public."ORDER" o ON ((c.customer_id = o.customer_id)))
     LEFT JOIN public.bill b ON ((o.order_id = b.order_id)))
  GROUP BY c.customer_id, c.first_name, c.last_name, c.email;


ALTER VIEW public.customer_order_summary OWNER TO admin;

